function AsciiLineChart({ data, title, width = 60, height = 15 }) {
  const { div, pre, span } = tags;
  const chars = ['_', '.', '-', '~', '^', '*'];

  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;

  const normalize = (val) => Math.floor(((val - min) / range) * (height - 1));

  let chart = Array(height).fill(null).map(() => Array(width).fill(' '));

  data.slice(-width).forEach((val, x) => {
    const y = height - 1 - normalize(val);
    chart[y][x] = '*';
  });

  const yAxis = Array(height).fill(null).map((_, i) => {
    const val = max - (i / (height - 1)) * range;
    return val.toFixed(1).padStart(6);
  });

  return div({ class: css('term-panel _p2') },
    title ? div({ class: css('_mb2 _fontbold') }, title) : null,
    pre({ class: css('_m0 _textsm') },
      ...chart.map((row, i) => div({}, `${yAxis[i]} │${row.join('')}`))
    ),
    div({ class: css('_textsm _fgmuted _mt1') },
      '       └' + '─'.repeat(width)
    )
  );
}

function AsciiBarChart({ data, title, maxWidth = 40 }) {
  const { div, span } = tags;
  const maxVal = Math.max(...data.map(d => d.value));

  return div({ class: css('term-panel _p2') },
    title ? div({ class: css('_mb2 _fontbold') }, title) : null,
    ...data.map(item => {
      const barLen = Math.round((item.value / maxVal) * maxWidth);
      const bar = '█'.repeat(barLen) + '░'.repeat(maxWidth - barLen);
      return div({ class: css('_flex _gap2 _textsm') },
        span({ class: css('_w[80px] _truncate') }, item.label),
        span({}, `[${bar}]`),
        span({ class: css('_fgmuted') }, item.value.toString())
      );
    })
  );
}

function Sparkline({ data, width = 20 }) {
  const { span } = tags;
  const braille = ['⣀', '⣄', '⣆', '⣇', '⣧', '⣷', '⣿'];
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;

  const chars = data.slice(-width).map(val => {
    const idx = Math.floor(((val - min) / range) * (braille.length - 1));
    return braille[idx];
  }).join('');

  return span({ class: css('term-sparkline') }, chars);
}

function BrailleChart({ data, title, width = 40, height = 10 }) {
  const { div, pre } = tags;
  // Braille base: U+2800, 2x4 dot matrix per character
  // Each character encodes 8 dots
  const BRAILLE_BASE = 0x2800;
  const DOT_PATTERNS = [
    [0x01, 0x08],
    [0x02, 0x10],
    [0x04, 0x20],
    [0x40, 0x80]
  ];

  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;

  // Create character grid
  let grid = Array(height).fill(null).map(() => Array(width).fill(BRAILLE_BASE));

  // Plot data points
  data.forEach((val, i) => {
    const x = Math.floor((i / data.length) * width * 2);
    const y = Math.floor(((max - val) / range) * height * 4);
    const charX = Math.floor(x / 2);
    const charY = Math.floor(y / 4);
    const dotX = x % 2;
    const dotY = y % 4;
    if (charX < width && charY < height) {
      grid[charY][charX] |= DOT_PATTERNS[dotY][dotX];
    }
  });

  return div({ class: css('term-panel _p2') },
    title ? div({ class: css('_mb2 _fontbold') }, title) : null,
    pre({ class: css('_m0') },
      ...grid.map(row => div({}, row.map(c => String.fromCharCode(c)).join('')))
    )
  );
}

function AsciiChart({ data, type = 'line' }) {
  switch (type) {
    case 'bar': return AsciiBarChart({ data });
    case 'sparkline': return Sparkline({ data });
    case 'braille': return BrailleChart({ data });
    default: return AsciiLineChart({ data });
  }
}
